using Microsoft.CodeAnalysis;using System.Reflection;namespace BgCommon.Script.Runtime;/// <summary>/// 表示库引用信息的记录类型./// </summary>[Serializable]public class LibraryRef : IComparable<LibraryRef>{    /// <summary>    /// Initializes a new instance of the <see cref="LibraryRef"/> class.    /// </summary>    public LibraryRef()    {    }    /// <summary>    /// Initializes a new instance of the <see cref="LibraryRef"/> class.    /// </summary>    /// <param name="kind">引用的类型（文件、框架或内存镜像）.</param>    /// <param name="value">引用的核心值（路径、全名或 Base64 字符串）.</param>    /// <param name="version">版本信息或友好名称（对于内存镜像作为标题使用）.</param>    public LibraryRef(RefKind kind, string value, string version = "")    {        this.Kind = kind;        this.Value = value;        this.Version = version;    }    /// <summary>    /// Gets 引用类型.    /// </summary>    public RefKind Kind { get; private set; }    /// <summary>    /// Gets 引用的具体值.    /// 根据 <see cref="Kind"/> 不同，可能为文件路径、程序集全名或 PE 镜像的 Base64 编码.    /// </summary>    public string Value { get; private set; } = string.Empty;    /// <summary>    /// Gets 版本信息或描述性标题.    /// </summary>    public string Version { get; private set; } = string.Empty;    /// <summary>    /// 克隆.    /// </summary>    /// <param name="src">源.</param>    /// <returns>克隆对象.</returns>    public LibraryRef Clone()    {        return new LibraryRef(this.Kind, this.Value, this.Version);    }    /// <summary>    /// 将当前实例与另一个 <see cref="LibraryRef"/> 进行比较，确定排序顺序.    /// </summary>    /// <param name="other">要比较的对象.</param>    /// <returns>小于零表示此实例位于被比较对象之前；零表示相等；大于零表示位于之后.</returns>    public int CompareTo(LibraryRef? other)    {        // 如果比较对象为空，按约定返回 1.        if (other == null)        {            return 1;        }        // 比较引用种类的优先级.        var kindComparisonResult = this.Kind.CompareTo(other.Kind);        if (kindComparisonResult != 0)        {            return kindComparisonResult;        }        // 比较引用内容的名称或路径.        var valueComparisonResult = StringComparer.Ordinal.Compare(this.Value, other.Value);        if (valueComparisonResult != 0)        {            return valueComparisonResult;        }        // 最后比较版本字符串.        return StringComparer.Ordinal.Compare(this.Version, other.Version);    }    /// <summary>    /// 将当前实例与另一个 <see cref="LibraryRef"/> 进行比较，确定是否相同.    /// </summary>    /// <param name="other">要比较的对象.</param>    /// <returns>返回是否相同.</returns>    public bool Equals(LibraryRef? other)    {        if (other is null)        {            return false;        }        if (ReferenceEquals(this, other))        {            return true;        }        // 逻辑必须与 CompareTo 保持一致        return Kind == other.Kind &&               string.Equals(Value, other.Value, StringComparison.Ordinal) &&               string.Equals(Version, other.Version, StringComparison.Ordinal);    }    /// <summary>    /// 将当前的引用定义解析为 Roslyn 编译器可识别的 <see cref="MetadataReference"/>.    /// </summary>    /// <returns>解析后的元数据引用实例.</returns>    /// <exception cref="NotSupportedException">当引用类型不受支持或无法获取程序集位置时抛出.</exception>    public MetadataReference Resolve()    {        return this.Kind switch        {            // 1. 文件引用逻辑            RefKind.Reference => MetadataReference.CreateFromFile(this.Value),            // 2. 运行时引用逻辑            RefKind.FrameworkReference => ResolveRuntimeAssembly(this.Value),            // 3. 内存镜像逻辑 (Base64 解码)            RefKind.MemoryImage => MetadataReference.CreateFromImage(Convert.FromBase64String(this.Value)),            // 4. NuGet 包引用逻辑 (通常需要外部 Resolver 预先下载到本地路径)            RefKind.PackageReference => throw new NotSupportedException("NuGet packages must be restored to file paths before resolving."),            _ => throw new ArgumentOutOfRangeException()        };    }    /// <inheritdoc/>    public override bool Equals(object? obj) => Equals(obj as LibraryRef);    /// <inheritdoc/>    public override int GetHashCode()    {        return HashCode.Combine(Kind, Value, Version);    }    /// <inheritdoc/>    public override string ToString()    {        return $"{this.Kind},{this.Value},{this.Version}";    }    /// <summary>    /// 重载 == 运算符.    /// </summary>    /// <param name="left">左侧对象.</param>    /// <param name="right">右侧对象.</param>    public static bool operator ==(LibraryRef? left, LibraryRef? right)    {        // 处理null情况，再调用 Equals 保证逻辑统一        if (left is null)        {            return right is null;        }        return left.Equals(right);    }    /// <summary>    /// 重载 != 运算符.    /// </summary>    /// <param name="left">左侧对象.</param>    /// <param name="right">右侧对象.</param>    public static bool operator !=(LibraryRef? left, LibraryRef? right)    {        return !(left == right);    }    /// <summary>    /// 判断左侧对象是否小于右侧对象.    /// </summary>    /// <param name="left">左侧对象.</param>    /// <param name="right">右侧对象.</param>    public static bool operator <(LibraryRef? left, LibraryRef? right) =>        ReferenceEquals(left, null) ? !ReferenceEquals(right, null) : left.CompareTo(right) < 0;    /// <summary>    /// 判断左侧对象是否小于或等于右侧对象.    /// </summary>    /// <param name="left">左侧对象.</param>    /// <param name="right">右侧对象.</param>    public static bool operator <=(LibraryRef? left, LibraryRef? right) =>        ReferenceEquals(left, null) || left.CompareTo(right) <= 0;    /// <summary>    /// 判断左侧对象是否大于右侧对象.    /// </summary>    /// <param name="left">左侧对象.</param>    /// <param name="right">右侧对象.</param>    public static bool operator >(LibraryRef? left, LibraryRef? right) =>        !ReferenceEquals(left, null) && left.CompareTo(right) > 0;    /// <summary>    /// 判断左侧对象是否大于或等于右侧对象.    /// </summary>    /// <param name="left">左侧对象.</param>    /// <param name="right">右侧对象.</param>    public static bool operator >=(LibraryRef? left, LibraryRef? right) =>        ReferenceEquals(left, null) ? ReferenceEquals(right, null) : left.CompareTo(right) >= 0;    /// <summary>    /// 内部逻辑：根据全名解析当前域中的程序集并转换为元数据引用.    /// </summary>    private static PortableExecutableReference ResolveRuntimeAssembly(string fullName)    {        var assembly = AppDomain.CurrentDomain.GetAssemblies()            .FirstOrDefault(a => a.GetName().FullName == fullName);        if (assembly == null)        {            try            {                assembly = Assembly.Load(fullName);            }            catch (Exception ex)            {                throw new FileNotFoundException($"Failed to load runtime assembly: {fullName}", ex);            }        }        if (string.IsNullOrEmpty(assembly.Location))        {            throw new NotSupportedException($"Assembly '{assembly.FullName}' is dynamic or in-memory without a physical location, which is not supported for compilation via location.");        }        return MetadataReference.CreateFromFile(assembly.Location);    }    /// <summary>    /// 创建普通文件引用实例.    /// </summary>    /// <param name="path">文件路径.</param>    /// <returns>库引用实例.</returns>    public static LibraryRef Reference(string path) => new(RefKind.Reference, path, string.Empty);    /// <summary>    /// 创建框架引用实例.    /// </summary>    /// <param name="id">框架标识符.</param>    /// <returns>库引用实例.</returns>    public static LibraryRef FrameworkReference(string id) => new(RefKind.FrameworkReference, id.ToLowerInvariant(), string.Empty);    /// <summary>    /// 创建包引用实例.    /// </summary>    /// <param name="id">包标识符.</param>    /// <param name="versionRange">版本范围描述.</param>    /// <returns>库引用实例.</returns>    public static LibraryRef PackageReference(string id, string versionRange) => new(RefKind.PackageReference, id.ToLowerInvariant(), versionRange);    /// <summary>    /// 创建一个基于内存字节流的程序集引用.    /// </summary>    /// <param name="title">该内存引用的友好显示名称.</param>    /// <param name="peImage">程序集的 PE 二进制数据.</param>    /// <returns>表示内存镜像引用的 <see cref="LibraryRef"/> 实例.</returns>    /// <remarks>内部会将字节数组转换为 Base64 字符串存储在 Value 属性中.</remarks>    public static LibraryRef MemoryReference(string title, byte[] peImage) => new(RefKind.MemoryImage, Convert.ToBase64String(peImage), title);}/// <summary>/// 引用类型枚举./// </summary>public enum RefKind{    /// <summary>    /// 普通文件引用.    /// </summary>    Reference,    /// <summary>    /// 框架引用.    /// </summary>    FrameworkReference,    /// <summary>    /// 内存镜像引用.    /// </summary>    MemoryImage,    /// <summary>    /// NuGet包引用.    /// </summary>    PackageReference,}